import sqlite3

def search(filters):
    conn = sqlite3.connect('database.db')
    cursor = conn.cursor()

    query = "SELECT * FROM users WHERE "

    params = []

    for filter in filters:
        field = filter['field']
        op = filter['op']
        value = filter['value']

        query += f"{field} {op} ? AND "
        params.append(value)

